// Verify HMAC signature from the threads-broadcast Edge Function.
// Matches the inquiry-router verification pattern — same shared secret
// (N8N_HMAC_SECRET) and the same X-Asset-Persona-Signature header.
const crypto = require('crypto');
const secret = $env.N8N_HMAC_SECRET;
const raw = $json.body || $input.first().binary?.data?.toString() || JSON.stringify($input.first().json);
const received = $input.first().json.headers?.['x-asset-persona-signature'] || $input.first().json['x-asset-persona-signature'];

const expected = crypto.createHmac('sha256', secret).update(raw).digest('hex');
if (!received || expected !== received) {
  throw new Error('HMAC signature invalid or missing');
}

// Parse and pass through
const payload = typeof raw === 'string' ? JSON.parse(raw) : raw;
return [{ json: payload }];

// Defense-in-depth payload validation. The Edge Function already enforces
// these, but never trust upstream blindly. Required: text present, non-empty,
// ≤ 500 chars (Threads hard cap). Also strip a couple of banned-words leakages
// just in case the model slipped — matches the frvnkfrmchicago voice rules.
const payload = $input.first().json;
const text = (payload.text || '').trim();

if (!text) {
  throw new Error('validation: empty text');
}
if (text.length > 500) {
  throw new Error(`validation: text exceeds 500 chars (got ${text.length})`);
}
// Reject hashtags / emojis defensively — the brand voice prompt forbids them
// but if any leak through, kill the post here rather than ship it.
if (/#\w/.test(text)) {
  throw new Error('validation: hashtags forbidden in @frvnkfrmchicago voice');
}

return [{ json: { ...payload, postText: text } }];
